// Parse .msg file content (Outlook format).
//
// Reads MSG files directly via the CFB (OLE Compound Document) format,
// extracting text properties and attachment metadata without the overhead
// of hex-encoding attachment binary data (which caused hangs on large files
// with the previous `msg_parser` dependency).
//
// Some MSG files have FAT headers declaring more sectors than the file
// actually contains.  The strict `cfb` crate rejects these.  When that
// happens we pad the data with zero bytes so the sector count matches
// the FAT and retry – the real streams are still within the original
// data range and parse correctly.
func ParseMsgContent(data []byte, fallback_codepage ...*uint32) (*EmailExtractionResult, error) {
    var fallback_codepageVal *uint32
    if len(fallback_codepage) > 0 {
        fallback_codepageVal = fallback_codepage[0]
    }
    cData := (*C.uchar)(unsafe.Pointer(&data[0]))

    ptr := C.kreuzberg_parse_msg_content(cData, cFallbackCodepageVal)
    if err := lastError(); err != nil {
        if ptr != nil {
            C.kreuzberg_email_extraction_result_free(ptr)
        }
        return nil, err
    }
    defer C.kreuzberg_email_extraction_result_free(ptr)
    return func() *EmailExtractionResult {
	jsonPtr := C.kreuzberg_email_extraction_result_to_json(ptr)
	if jsonPtr == nil { return nil }
	defer C.kreuzberg_free_string(jsonPtr)
	var result EmailExtractionResult
	if err := json.Unmarshal([]byte(C.GoString(jsonPtr)), &result); err != nil { return nil }
	return &result
}(), nil
}


