// Build text output from email extraction result
func BuildEmailTextOutput(result EmailExtractionResult) *string {
    jsonBytescResult, err := json.Marshal(result)
    if err != nil {
        panic(fmt.Sprintf("failed to marshal: %v", err))
    }
    tmpStrcResult := C.CString(string(jsonBytescResult))
    cResult := C.kreuzberg_email_extraction_result_from_json(tmpStrcResult)
    C.free(unsafe.Pointer(tmpStrcResult))
    defer C.kreuzberg_email_extraction_result_free(cResult)

    ptr := C.kreuzberg_build_email_text_output(cResult)
    defer C.kreuzberg_free_string(ptr)
    return func() *string { v := C.GoString(ptr); return &v }()
}


