// # Safety
//
// This function is safe and does not use any unsafe code directly. The underlying
// SIMD validation (when enabled) is contained within the simdutf8 crate and is safe.
func FromUtf8(bytes []byte) (*string, error) {
    cBytes := (*C.uchar)(unsafe.Pointer(&bytes[0]))

    ptr := C.kreuzberg_from_utf8(cBytes)
    if err := lastError(); err != nil {
        if ptr != nil {
            C.kreuzberg_free_string(ptr)
        }
        return nil, err
    }
    defer C.kreuzberg_free_string(ptr)
    return func() *string { v := C.GoString(ptr); return &v }(), nil
}


